            [<Config.Form>]
            StatementDescriptor: string option
            /// Provides information about a card charge. Concatenated to the account's [statement descriptor prefix](https://docs.stripe.com/get-started/account/statement-descriptors#static) to form the complete statement descriptor that appears on the customer's statement.
            [<Config.Form>]
            StatementDescriptorSuffix: string option
            /// The parameters that you can use to automatically create a transfer after the payment
            /// is captured. Learn more about the [use case for connected accounts](https://docs.stripe.com/payments/connected-accounts).
            [<Config.Form>]
            TransferData: Capture'TransferData option
        }

    module CaptureOptions =
        let create
            (
                intent: string
            ) : CaptureOptions
            =
            {
              Intent = intent
              AmountDetails = None
              AmountToCapture = None
              ApplicationFeeAmount = None
              Expand = None
              FinalCapture = None
              Hooks = None
              Metadata = None
              PaymentDetails = None
              StatementDescriptor = None
              StatementDescriptorSuffix = None
              TransferData = None
            }

    ///<p>Capture the funds of an existing uncaptured PaymentIntent when its status is <code>requires_capture</code>.</p>
    ///<p>Uncaptured PaymentIntents are cancelled a set number of days (7 by default) after their creation.</p>
    ///<p>Learn more about <a href="/docs/payments/capture-later">separate authorization and capture</a>.</p>
    let Capture settings (options: CaptureOptions) =
        $"/v1/payment_intents/{options.Intent}/capture"
        |> RestApi.postAsync<_, PaymentIntent> settings (Map.empty) options

