    type UpdateOptions =
        {
            [<Config.Path>]
            PaymentLink: string
            /// Whether the payment link's `url` is active. If `false`, customers visiting the URL will be shown a page saying that the link has been deactivated.
            [<Config.Form>]
            Active: bool option
            /// Behavior after the purchase is complete.
            [<Config.Form>]
            AfterCompletion: Update'AfterCompletion option
            /// Enables user redeemable promotion codes.
            [<Config.Form>]
            AllowPromotionCodes: bool option
            /// Configuration for automatic tax collection.
            [<Config.Form>]
            AutomaticTax: Update'AutomaticTax option
            /// Configuration for collecting the customer's billing address. Defaults to `auto`.
            [<Config.Form>]
            BillingAddressCollection: Update'BillingAddressCollection option
            /// Collect additional information from your customer using custom fields. Up to 3 fields are supported. You can't set this parameter if `ui_mode` is `custom`.
            [<Config.Form>]
            CustomFields: Choice<Update'CustomFields list,string> option
            /// Display additional text for your customers using custom text. You can't set this parameter if `ui_mode` is `custom`.
            [<Config.Form>]
            CustomText: Update'CustomText option
            /// Configures whether [checkout sessions](https://docs.stripe.com/api/checkout/sessions) created by this payment link create a [Customer](https://docs.stripe.com/api/customers).
            [<Config.Form>]
            CustomerCreation: Update'CustomerCreation option
            /// Specifies which fields in the response should be expanded.
            [<Config.Form>]
            Expand: string list option
            /// The custom message to be displayed to a customer when a payment link is no longer active.
            [<Config.Form>]
            InactiveMessage: Choice<string,string> option
            /// Generate a post-purchase Invoice for one-time payments.
            [<Config.Form>]
            InvoiceCreation: Update'InvoiceCreation option
            /// The line items representing what is being sold. Each line item represents an item being sold. Up to 20 line items are supported.
            [<Config.Form>]
            LineItems: Update'LineItems list option
            /// Set of [key-value pairs](https://docs.stripe.com/api/metadata) that you can attach to an object. This can be useful for storing additional information about the object in a structured format. Individual keys can be unset by posting an empty value to them. All keys can be unset by posting an empty value to `metadata`. Metadata associated with this Payment Link will automatically be copied to [checkout sessions](https://docs.stripe.com/api/checkout/sessions) created by this payment link.
            [<Config.Form>]
            Metadata: Map<string, string> option
            /// Controls settings applied for collecting the customer's name.
            [<Config.Form>]
            NameCollection: Choice<Update'NameCollectionNameCollectionParams,string> option
            /// A list of optional items the customer can add to their order at checkout. Use this parameter to pass one-time or recurring [Prices](https://docs.stripe.com/api/prices).
            /// There is a maximum of 10 optional items allowed on a payment link, and the existing limits on the number of line items allowed on a payment link apply to the combined number of line items and optional items.
            /// There is a maximum of 20 combined line items and optional items.
            [<Config.Form>]
            OptionalItems: Choice<Update'OptionalItems list,string> option
            /// A subset of parameters to be passed to PaymentIntent creation for Checkout Sessions in `payment` mode.
            [<Config.Form>]
            PaymentIntentData: Update'PaymentIntentData option
            /// Specify whether Checkout should collect a payment method. When set to `if_required`, Checkout will not collect a payment method when the total due for the session is 0.This may occur if the Checkout Session includes a free trial or a discount.
            /// Can only be set in `subscription` mode. Defaults to `always`.
            /// If you'd like information on how to collect a payment method outside of Checkout, read the guide on [configuring subscriptions with a free trial](https://docs.stripe.com/payments/checkout/free-trials).
            [<Config.Form>]
            PaymentMethodCollection: Update'PaymentMethodCollection option
            /// The list of payment method types that customers can use. Pass an empty string to enable dynamic payment methods that use your [payment method settings](https://dashboard.stripe.com/settings/payment_methods).
            [<Config.Form>]
            PaymentMethodTypes: Choice<Update'PaymentMethodTypes list,string> option
            /// Controls phone number collection settings during checkout.
            /// We recommend that you review your privacy policy and check with your legal contacts.
            [<Config.Form>]
            PhoneNumberCollection: Update'PhoneNumberCollection option
            /// Settings that restrict the usage of a payment link.
            [<Config.Form>]
            Restrictions: Choice<Update'RestrictionsRestrictionsParams,string> option
            /// Configuration for collecting the customer's shipping address.
            [<Config.Form>]
            ShippingAddressCollection: Choice<Update'ShippingAddressCollectionShippingAddressCollectionParams,string> option
            /// Describes the type of transaction being performed in order to customize relevant text on the page, such as the submit button. Changing this value will also affect the hostname in the [url](https://docs.stripe.com/api/payment_links/payment_links/object#url) property (example: `donate.stripe.com`).
            [<Config.Form>]
            SubmitType: Update'SubmitType option
            /// When creating a subscription, the specified configuration data will be used. There must be at least one line item with a recurring price to use `subscription_data`.
            [<Config.Form>]
            SubscriptionData: Update'SubscriptionData option
            /// Controls tax ID collection during checkout.
            [<Config.Form>]
            TaxIdCollection: Update'TaxIdCollection option
        }

