            [<Config.Form>]
            InvoiceNow: bool option
            /// If the subscription schedule is `active`, indicates if the cancellation should be prorated. Defaults to `true`.
            [<Config.Form>]
            Prorate: bool option
        }

    module CancelOptions =
        let create
            (
                schedule: string
            ) : CancelOptions
            =
            {
              Schedule = schedule
              Expand = None
              InvoiceNow = None
              Prorate = None
